29	/*!
30	 * \brief The CUDA kernel that merges the self-attention state of two index sets A and B.
31	 * \tparam vec_size The vector size used in the kernel.
32	 * \tparam DTypeIn The data type of v_a and v_b.
33	 * \tparam DTypeO The data type of v_merged.
34	 * \param v_a The partial v of index set A. (n, h, d)
35	 * \param s_a The logsumexp value of index set A. (n, h)
36	 * \param v_b The partial v of index set B. (n, h, d)
37	 * \param s_b The logsumexp value of index set B. (n, h)
38	 * \param v_merged The merged v of index set A union B. (n, h, d)
39	 * \param s_merged The merged logsumexp value of index set A union B. (n, h)
40	 * \param num_heads The number of heads of v_a and v_b.
41	 * \param head_dim The dimension of each head.
42	 * \note Both s_a and s_b are logsumexp values with base 2.
43	 */
44	template <uint32_t vec_size, typename DTypeIn, typename DTypeO>
45	__global__ void MergeStateKernel(DTypeIn* __restrict__ v_a, float* __restrict__ s_a,
46	                                 DTypeIn* __restrict__ v_b, float* __restrict__ s_b,
47	                                 DTypeO* __restrict__ v_merged, float* __restrict__ s_merged,
48	                                 uint32_t num_heads, uint32_t head_dim) {
49	  uint32_t tx = threadIdx.x, ty = threadIdx.y;
50	  uint32_t pos = blockIdx.x;
51	  uint32_t head_idx = ty;
52	
53	  float s_a_val = s_a[pos * num_heads + head_idx];
54	  float s_b_val = s_b[pos * num_heads + head_idx];
55	  float s_max = max(s_a_val, s_b_val);
56	  s_a_val = math::ptx_exp2(s_a_val - s_max);
57	  s_b_val = math::ptx_exp2(s_b_val - s_max);
58	  float a_scale = s_a_val / (s_a_val + s_b_val);
59	  float b_scale = s_b_val / (s_a_val + s_b_val);
60	  vec_t<float, vec_size> v_a_vec, v_b_vec, v_merged_vec;
61	  v_a_vec.cast_load(v_a + (pos * num_heads + head_idx) * head_dim + tx * vec_size);
62	  v_b_vec.cast_load(v_b + (pos * num_heads + head_idx) * head_dim + tx * vec_size);
63	#pragma unroll
64	  for (uint32_t i = 0; i < vec_size; ++i) {
65	    v_merged_vec[i] = a_scale * v_a_vec[i] + b_scale * v_b_vec[i];
66	  }
67	  v_merged_vec.cast_store(v_merged + (pos * num_heads + head_idx) * head_dim + tx * vec_size);
68	  if (s_merged != nullptr) {
69	    s_merged[pos * num_heads + head_idx] = math::ptx_log2(s_a_val + s_b_val) + s_max;
70	  }
71	}
