73	/*!
74	 * \brief The CUDA kernel that merges the self-attention state with another state in-place.
75	 * \tparam vec_size The vector size used in the kernel.
76	 * \tparam DType The data type of v and v_other.
77	 * \param v The partial v to be updated in-place. (n, h, d)
78	 * \param s The logsumexp value to be updated in-place. (n, h)
79	 * \param v_other The other v to be merged. (n, h, d)
80	 * \param s_other The other logsumexp value to be merged. (n, h)
81	 * \param mask Optional mask of whether to merge given sequences or not. (n)
82	 * \param num_heads The number of heads of v and v_other.
83	 * \param head_dim The dimension of each head.
84	 * \note Both s and s_other are logsumexp values with base 2.
85	 */
86	template <uint32_t vec_size, typename DType>
87	__global__ void MergeStateInPlaceKernel(DType* __restrict__ v, float* __restrict__ s,
88	                                        DType* __restrict__ v_other, float* __restrict__ s_other,
89	                                        uint8_t* __restrict__ mask, uint32_t num_heads,
90	                                        uint32_t head_dim) {
91	  uint32_t pos = blockIdx.x;
92	
93	  if (mask != nullptr && mask[pos] == 0) return;
94	
95	  uint32_t tx = threadIdx.x, ty = threadIdx.y;
96	  uint32_t head_idx = ty;
97	
98	  float s_val = s[pos * num_heads + head_idx];
99	  float s_other_val = s_other[pos * num_heads + head_idx];
100	  float s_max = max(s_val, s_other_val);
101	  s_val = math::ptx_exp2(s_val - s_max);
102	  s_other_val = math::ptx_exp2(s_other_val - s_max);
103	  float scale = s_val / (s_val + s_other_val);
104	  float other_scale = s_other_val / (s_val + s_other_val);
105	  vec_t<float, vec_size> v_vec, v_other_vec;
106	  v_vec.cast_load(v + (pos * num_heads + head_idx) * head_dim + tx * vec_size);
107	  v_other_vec.cast_load(v_other + (pos * num_heads + head_idx) * head_dim + tx * vec_size);
108	#pragma unroll
109	  for (uint32_t i = 0; i < vec_size; ++i) {
110	    v_vec[i] = scale * v_vec[i] + other_scale * v_other_vec[i];
111	  }
112	  v_vec.cast_store(v + (pos * num_heads + head_idx) * head_dim + tx * vec_size);
113	  if (s != nullptr) {
114	    s[pos * num_heads + head_idx] = math::ptx_log2(s_val + s_other_val) + s_max;
115	  }
116	}
