118	template <uint32_t bdx, uint32_t bdy, uint32_t vec_size, typename DTypeIn>
119	__device__ __forceinline__ void threadblock_sync_state(state_t<vec_size>& st, DTypeIn* v_smem,
120	                                                       float* s_smem,
121	                                                       const uint32_t tx = threadIdx.x,
122	                                                       const uint32_t ty = threadIdx.y) {
123	  constexpr uint32_t head_dim = vec_size * bdx;
124	  st.o.cast_store(v_smem + ty * head_dim + tx * vec_size);
125	  s_smem[ty] = st.get_lse();
126	  st.init();
127	  __syncthreads();
128	
129	#pragma unroll
130	  for (uint32_t iter = 0; iter < bdy; ++iter) {
131	    float s = s_smem[iter];
132	    vec_t<float, vec_size> v;
133	    v.cast_load(v_smem + iter * head_dim + tx * vec_size);
134	    st.merge(v, s, 1);
135	  }
136	}
