138	template <uint32_t bdx, uint32_t bdy, uint32_t vec_size, typename DTypeIn>
139	__device__ __forceinline__ void warp_sync_state(state_t<vec_size>& st, DTypeIn* v_smem,
140	                                                float* s_smem, const uint32_t tx = threadIdx.x,
141	                                                const uint32_t ty = threadIdx.y) {
142	  constexpr uint32_t head_dim = vec_size * bdx;
143	  st.o.cast_store(v_smem + ty * head_dim + tx * vec_size);
144	  s_smem[ty] = st.get_lse();
145	  st.init();
146	  __syncwarp();
147	
148	#pragma unroll
149	  for (uint32_t iter = 0; iter < bdy; ++iter) {
150	    float s = s_smem[iter];
151	    vec_t<float, vec_size> v;
152	    v.cast_load(v_smem + iter * head_dim + tx * vec_size);
153	    st.merge(v, s, 1);
154	  }
155	}
