157	template <uint32_t bdx, uint32_t bdy, uint32_t vec_size, typename DTypeIn>
158	__device__ __forceinline__ void threadblock_sum(vec_t<float, vec_size>& v, DTypeIn* v_smem) {
159	  const uint32_t tx = threadIdx.x, ty = threadIdx.y;
160	  constexpr uint32_t head_dim = vec_size * bdx;
161	  v.cast_store(v_smem + ty * head_dim + tx * vec_size);
162	  v.fill(DTypeIn(0.f));
163	  __syncthreads();
164	
165	#pragma unroll
166	  for (uint32_t iter = 0; iter < bdy; ++iter) {
167	    vec_t<float, vec_size> v_iter;
168	    v_iter.cast_load(v_smem + iter * head_dim + tx * vec_size);
169	#pragma unroll
170	    for (uint32_t i = 0; i < vec_size; ++i) {
171	      v[i] += v_iter[i];
172	    }
173	  }
174	}
