176	template <uint32_t vec_size, typename DTypeIn, typename DTypeO>
177	__global__ void AttentionSumKernel(DTypeIn* __restrict__ V, DTypeO* __restrict__ v_sum,
178	                                   uint32_t num_index_sets, uint32_t num_heads, uint32_t head_dim) {
179	  uint32_t tx = threadIdx.x, ty = threadIdx.y;
180	  uint32_t pos = blockIdx.x;
181	  uint32_t head_idx = ty;
182	
183	  if (num_index_sets == 0) {
184	    vec_t<DTypeO, vec_size> v;
185	    v.fill(DTypeO(0.f));
186	    v.store(v_sum + (pos * num_heads + head_idx) * head_dim + tx * vec_size);
187	    return;
188	  }
189	
190	  if (num_index_sets == 1) {
191	    vec_t<DTypeO, vec_size> v;
192	    v.cast_load(V + (pos * num_heads + head_idx) * head_dim + tx * vec_size);
193	    v.store(v_sum + (pos * num_heads + head_idx) * head_dim + tx * vec_size);
194	    return;
195	  }
196	
197	  vec_t<float, vec_size> v_sum_vec;
198	  v_sum_vec.fill(0.f);
199	#pragma unroll 2
200	  for (uint32_t iter = 0; iter < num_index_sets; ++iter) {
201	    vec_t<float, vec_size> v;
202	    v.cast_load(V + ((pos * num_index_sets + iter) * num_heads + head_idx) * head_dim +
203	                tx * vec_size);
204	#pragma unroll
205	    for (uint32_t i = 0; i < vec_size; ++i) {
206	      v_sum_vec[i] += v[i];
207	    }
208	  }
209	
210	  v_sum_vec.cast_store(v_sum + (pos * num_heads + head_idx) * head_dim + tx * vec_size);
211	}
