213	template <uint32_t vec_size, typename DTypeIn, typename DTypeO>
214	__global__ void MergeStatesKernel(DTypeIn* __restrict__ V, float* __restrict__ S,
215	                                  DTypeO* __restrict__ v_merged, float* __restrict__ s_merged,
216	                                  uint32_t num_index_sets, uint32_t num_heads, uint32_t head_dim) {
217	  uint32_t tx = threadIdx.x, ty = threadIdx.y;
218	  uint32_t pos = blockIdx.x;
219	  uint32_t head_idx = ty;
220	
221	  if (num_index_sets == 0) {
222	    vec_t<DTypeO, vec_size> v;
223	    v.fill(DTypeO(0.f));
224	    v.store(v_merged + (pos * num_heads + head_idx) * head_dim + tx * vec_size);
225	    if (s_merged != nullptr) {
226	      s_merged[pos * num_heads + head_idx] = -math::inf;
227	    }
228	    return;
229	  }
230	
231	  if (num_index_sets == 1) {
232	    vec_t<DTypeO, vec_size> v;
233	    v.cast_load(V + (pos * num_heads + head_idx) * head_dim + tx * vec_size);
234	    v.store(v_merged + (pos * num_heads + head_idx) * head_dim + tx * vec_size);
235	    if (s_merged != nullptr) {
236	      s_merged[pos * num_heads + head_idx] = S[pos * num_heads + head_idx];
237	    }
238	    return;
239	  }
240	
241	  state_t<vec_size> st;
242	#pragma unroll 2
243	  for (uint32_t iter = 0; iter < num_index_sets; ++iter) {
244	    float s = S[(pos * num_index_sets + iter) * num_heads + head_idx];
245	    vec_t<float, vec_size> v;
246	    v.cast_load(V + ((pos * num_index_sets + iter) * num_heads + head_idx) * head_dim +
247	                tx * vec_size);
248	    st.merge(v, s, 1);
249	  }
250	
251	  st.normalize();
252	  st.o.cast_store(v_merged + (pos * num_heads + head_idx) * head_dim + tx * vec_size);
253	  if (s_merged != nullptr) {
254	    s_merged[pos * num_heads + head_idx] = st.get_lse();
255	  }
256	}
