258	/*!
259	 * \brief The CUDA kernel that merges self-attention states of a list of index sets,
260	 *   accelerated for larger number of index sets.
261	 * \tparam vec_size The vector size used in the kernel.
262	 * \tparam bdx The blockDim.x used in the kernel.
263	 * \tparam bdy The blockDim.y used in the kernel.
264	 * \tparam num_smem_stages The number of stages of shared memory used in the kernel.
265	 * \tparam DTypeIn The data type of v.
266	 * \tparam DTypeO The data type of v_merged.
267	 * \param V The partial v of index sets. (n, num_index_sets, h, d)
268	 * \param S The logsumexp value of index sets. (n, num_index_sets, h)
269	 * \param v_merged The merged v of index sets union. (n, h, d)
270	 * \param s_merged The merged logsumexp value of index sets union. (n, h)
271	 * \param num_heads The number of heads of v.
272	 * \param head_dim The dimension of each head.
273	 * \note s are logsumexp values with base 2.
274	 */
275	template <uint32_t vec_size, uint32_t bdx, uint32_t bdy, uint32_t num_smem_stages, typename DTypeIn,
276	          typename DTypeO>
277	__global__ void MergeStatesLargeNumIndexSetsKernel(DTypeIn* __restrict__ V, float* __restrict__ S,
278	                                                   DTypeO* __restrict__ v_merged,
279	                                                   float* __restrict__ s_merged,
280	                                                   uint32_t num_index_sets, uint32_t num_heads) {
281	  uint32_t tx = threadIdx.x, ty = threadIdx.y;
282	  uint32_t pos = blockIdx.x;
283	  uint32_t head_idx = blockIdx.y;
284	  state_t<vec_size> st;
285	  constexpr uint32_t vec_bits = sizeof(DTypeIn) * vec_size * 8;
286	  constexpr uint32_t head_dim = vec_size * bdx;
287	
288	  extern __shared__ uint8_t smem[];
289	  DTypeIn* v_smem = (DTypeIn*)smem;
290	  float* s_smem = (float*)(smem + num_smem_stages * bdy * head_dim * sizeof(DTypeIn));
291	
292	#pragma unroll
293	  for (uint32_t iter = 0; iter < num_smem_stages; ++iter) {
294	    cp_async::pred_load<vec_bits, PrefetchMode::kPrefetch, SharedMemFillMode::kNoFill>(
295	        v_smem + (iter * bdy + ty) * head_dim + tx * vec_size,
296	        V + ((pos * num_index_sets + (iter * bdy + ty)) * num_heads + head_idx) * head_dim +
297	            tx * vec_size,
298	        (iter * bdy + ty) < num_index_sets);
299	    cp_async::commit_group();
300	  }
301	#pragma unroll 4
302	  for (uint32_t iter = 0; iter < ceil_div(num_index_sets, bdy); ++iter) {
303	    if (iter % bdx == 0) {
304	      s_smem[ty * bdx + tx] =
305	          iter * bdy + (ty * bdx + tx) < num_index_sets
306	              ? S[(pos * num_index_sets + (iter * bdy + ty * bdx + tx)) * num_heads + head_idx]
307	              : 0.f;
308	      __syncthreads();
309	    }
310	    cp_async::wait_group<num_smem_stages - 1>();
311	    __syncthreads();
312	    vec_t<float, vec_size> v;
313	    v.cast_load(v_smem + ((iter % num_smem_stages) * bdy + ty) * head_dim + tx * vec_size);
314	    if (iter * bdy + ty < num_index_sets) {
315	      float s = s_smem[(iter % bdx) * bdy + ty];
316	      st.merge(v, s, 1);
317	    }
318	    __syncthreads();
319	    cp_async::pred_load<vec_bits, PrefetchMode::kPrefetch, SharedMemFillMode::kNoFill>(
320	        v_smem + ((iter % num_smem_stages) * bdy + ty) * head_dim + tx * vec_size,
321	        V +
322	            ((pos * num_index_sets + ((iter + num_smem_stages) * bdy + ty)) * num_heads +
323	             head_idx) *
324	                head_dim +
325	            tx * vec_size,
326	        (iter + num_smem_stages) * bdy + ty < num_index_sets);
327	    cp_async::commit_group();
328	  }
329	  cp_async::wait_group<0>();
330	  __syncthreads();
331	
332	  st.normalize();
333	  threadblock_sync_state<bdx, bdy, vec_size>(st, v_smem, s_smem);
334	  st.normalize();
335	
336	  st.o.cast_store(v_merged + (pos * num_heads + head_idx) * head_dim + tx * vec_size);
337	  if (s_merged != nullptr) {
338	    s_merged[pos * num_heads + head_idx] = st.get_lse();
339	  }
340	}
