342	/*!
343	 * \brief The CUDA kernel to merge self-attention states of multiple index sets, the number of
344	 * index sets at each position might vary.
345	 *
346	 * For CUDA graph support, the kernel can be built with a maximum sequence length and executed
347	 * using a truncated, dynamic sequence length passed through `seq_len_ptr`.
348	 *
349	 * \tparam vec_size The vector size used in the kernel.
350	 * \tparam bdx The blockDim.x used in the kernel.
351	 * \tparam bdy The blockDim.y used in the kernel.
352	 * \tparam num_smem_stages The number of stages of shared memory used in the kernel.
353	 * \tparam DTypeIn The data type of v.
354	 * \tparam DTypeO The data type of v_merged.
355	 * \param V The partial v of index sets. (nnz, h, d)
356	 * \param S The logsumexp value of index sets. (nnz, h)
357	 * \param indptr The start offsets of each position in the variable length array.
358	 * \param v_merged The merged v of index sets union. (n, h, d)
359	 * \param s_merged The merged logsumexp value of index sets union. (n, h)
360	 * \param max_seq_len The maximum sequence length supported by the kernel.
361	 * \param seq_len_ptr The current sequence length (number of positions populated in indptr).
362	 * \param num_heads The number of heads of v.
363	 * \param head_dim The dimension of each head.
364	 * \note s are logsumexp values with base 2.
365	 */
366	template <uint32_t vec_size, uint32_t bdx, uint32_t bdy, uint32_t num_smem_stages, typename DTypeIn,
367	          typename DTypeO, typename IdType>
368	__global__ void PersistentVariableLengthMergeStatesKernel(
369	    DTypeIn* __restrict__ V, float* __restrict__ S, IdType* indptr, DTypeO* __restrict__ v_merged,
370	    float* __restrict__ s_merged, uint32_t max_seq_len, uint32_t* __restrict__ seq_len_ptr,
371	    uint32_t num_heads) {
372	  uint32_t tx = threadIdx.x, ty = threadIdx.y;
373	  uint32_t cta_id = blockIdx.x;
374	  uint32_t num_ctas = gridDim.x;
375	  const uint32_t seq_len = seq_len_ptr ? *seq_len_ptr : max_seq_len;
376	  uint32_t num_iters = ceil_div(seq_len * num_heads, num_ctas);
377	  constexpr uint32_t vec_bits = sizeof(DTypeIn) * vec_size * 8;
378	  constexpr uint32_t head_dim = vec_size * bdx;
379	  extern __shared__ uint8_t smem[];
380	  DTypeIn* v_smem = (DTypeIn*)smem;
381	  float* s_smem = (float*)(smem + num_smem_stages * bdy * head_dim * sizeof(DTypeIn));
382	
383	#if (__CUDACC_VER_MAJOR__ >= 12 && defined(__CUDA_ARCH__) && (__CUDA_ARCH__ >= 900))
384	  asm volatile("griddepcontrol.wait;");
385	#endif
386	
387	#pragma unroll 1
388	  for (uint32_t i = cta_id; i < seq_len * num_heads; i += num_ctas) {
389	    // NOTE (Yilong): necessary to prevent hazard on smaller `num_index_sets`
390	    __syncthreads();
391	
392	    uint32_t pos = i / num_heads;
393	    uint32_t head_idx = i % num_heads;
394	    state_t<vec_size> st;
395	    const uint32_t num_index_sets = indptr[pos + 1] - indptr[pos];
396	
397	    if (num_index_sets == 0) {
398	      vec_t<DTypeO, vec_size> v;
399	      v.fill(DTypeO(0.f));
400	      v.store(v_merged + (pos * num_heads + head_idx) * head_dim + tx * vec_size);
401	      if (s_merged != nullptr) {
402	        s_merged[pos * num_heads + head_idx] = -math::inf;
403	      }
404	      continue;
405	    }
406	
407	    if (num_index_sets == 1) {
408	      vec_t<DTypeO, vec_size> v;
409	      v.cast_load(V + (indptr[pos] * num_heads + head_idx) * head_dim + tx * vec_size);
410	      v.store(v_merged + (pos * num_heads + head_idx) * head_dim + tx * vec_size);
411	      if (s_merged != nullptr) {
412	        s_merged[pos * num_heads + head_idx] = S[indptr[pos] * num_heads + head_idx];
413	      }
414	      continue;
415	    }
416	
417	#pragma unroll
418	    for (uint32_t iter = 0; iter < num_smem_stages; ++iter) {
419	      cp_async::pred_load<vec_bits, PrefetchMode::kPrefetch, SharedMemFillMode::kNoFill>(
420	          v_smem + (iter * bdy + ty) * head_dim + tx * vec_size,
421	          V + ((indptr[pos] + (iter * bdy + ty)) * num_heads + head_idx) * head_dim + tx * vec_size,
422	          (iter * bdy + ty) < num_index_sets);
423	      cp_async::commit_group();
424	    }
425	#pragma unroll 4
426	    for (uint32_t iter = 0; iter < ceil_div(num_index_sets, bdy); ++iter) {
427	      if (iter % bdx == 0) {
428	        s_smem[ty * bdx + tx] =
429	            iter * bdy + (ty * bdx + tx) < num_index_sets
430	                ? S[(indptr[pos] + (iter * bdy + ty * bdx + tx)) * num_heads + head_idx]
431	                : 0.f;
432	        __syncthreads();
433	      }
434	      cp_async::wait_group<num_smem_stages - 1>();
435	      __syncthreads();
436	      vec_t<float, vec_size> v;
437	      v.cast_load(v_smem + ((iter % num_smem_stages) * bdy + ty) * head_dim + tx * vec_size);
438	      if (iter * bdy + ty < num_index_sets) {
439	        float s = s_smem[(iter % bdx) * bdy + ty];
440	        st.merge(v, s, 1);
441	      }
442	      __syncthreads();
443	      cp_async::pred_load<vec_bits, PrefetchMode::kPrefetch, SharedMemFillMode::kNoFill>(
444	          v_smem + ((iter % num_smem_stages) * bdy + ty) * head_dim + tx * vec_size,
445	          V +
446	              ((indptr[pos] + ((iter + num_smem_stages) * bdy + ty)) * num_heads + head_idx) *
447	                  head_dim +
448	              tx * vec_size,
449	          (iter + num_smem_stages) * bdy + ty < num_index_sets);
450	      cp_async::commit_group();
451	    }
452	    cp_async::wait_group<0>();
453	    __syncthreads();
454	
455	    st.normalize();
456	    threadblock_sync_state<bdx, bdy, vec_size>(st, v_smem, s_smem);
457	    st.normalize();
458	
459	    st.o.cast_store(v_merged + (pos * num_heads + head_idx) * head_dim + tx * vec_size);
460	    if (s_merged != nullptr) {
461	      s_merged[pos * num_heads + head_idx] = st.get_lse();
462	    }
463	  }
464	#if (__CUDACC_VER_MAJOR__ >= 12 && defined(__CUDA_ARCH__) && (__CUDA_ARCH__ >= 900))
465	  asm volatile("griddepcontrol.launch_dependents;");
466	#endif
467	}
468	
469	template <uint32_t vec_size, uint32_t bdx, uint32_t bdy, uint32_t num_smem_stages, typename DTypeIn,
470	          typename DTypeO, typename IdType>
471	__global__ void PersistentVariableLengthAttentionSumKernel(DTypeIn* __restrict__ V, IdType* indptr,
472	                                                           DTypeO* __restrict__ v_sum,
473	                                                           uint32_t max_seq_len,
474	                                                           uint32_t* __restrict__ seq_len_ptr,
475	                                                           uint32_t num_heads) {
476	  uint32_t tx = threadIdx.x, ty = threadIdx.y;
477	  uint32_t cta_id = blockIdx.x;
478	  uint32_t num_ctas = gridDim.x;
479	  const uint32_t seq_len = seq_len_ptr ? *seq_len_ptr : max_seq_len;
480	  uint32_t num_iters = ceil_div(seq_len * num_heads, num_ctas);
481	  constexpr uint32_t vec_bits = sizeof(DTypeIn) * vec_size * 8;
482	  constexpr uint32_t head_dim = vec_size * bdx;
483	  extern __shared__ uint8_t smem[];
484	  DTypeIn* v_smem = (DTypeIn*)smem;
485	
486	  vec_t<float, vec_size> v_sum_vec;
487	#if (__CUDACC_VER_MAJOR__ >= 12 && defined(__CUDA_ARCH__) && (__CUDA_ARCH__ >= 900))
488	  asm volatile("griddepcontrol.wait;");
489	#endif
490	
491	#pragma unroll 1
492	  for (uint32_t i = cta_id; i < seq_len * num_heads; i += num_ctas) {
493	    __syncthreads();
494	
495	    uint32_t pos = i / num_heads;
496	    uint32_t head_idx = i % num_heads;
497	    const uint32_t num_index_sets = indptr[pos + 1] - indptr[pos];
498	
499	    if (num_index_sets == 0) {
500	      vec_t<DTypeO, vec_size> v;
501	      v.fill(DTypeO(0.f));
502	      v.store(v_sum + (pos * num_heads + head_idx) * head_dim + tx * vec_size);
503	      continue;
504	    }
505	
506	    if (num_index_sets == 1) {
507	      vec_t<DTypeO, vec_size> v;
508	      v.cast_load(V + (indptr[pos] * num_heads + head_idx) * head_dim + tx * vec_size);
509	      v.store(v_sum + (pos * num_heads + head_idx) * head_dim + tx * vec_size);
510	      continue;
511	    }
512	
513	#pragma unroll
514	    for (uint32_t iter = 0; iter < num_smem_stages; ++iter) {
515	      cp_async::pred_load<vec_bits, PrefetchMode::kPrefetch, SharedMemFillMode::kNoFill>(
516	          v_smem + (iter * bdy + ty) * head_dim + tx * vec_size,
517	          V + ((indptr[pos] + (iter * bdy + ty)) * num_heads + head_idx) * head_dim + tx * vec_size,
518	          (iter * bdy + ty) < num_index_sets);
519	      cp_async::commit_group();
520	    }
521	#pragma unroll 4
522	    for (uint32_t iter = 0; iter < ceil_div(num_index_sets, bdy); ++iter) {
523	      cp_async::wait_group<num_smem_stages - 1>();
524	      __syncthreads();
525	      vec_t<float, vec_size> v;
526	      v.cast_load(v_smem + ((iter % num_smem_stages) * bdy + ty) * head_dim + tx * vec_size);
527	      if (iter * bdy + ty < num_index_sets) {
528	#pragma unroll
529	        for (uint32_t i = 0; i < vec_size; ++i) {
530	          v_sum_vec[i] += v[i];
531	        }
532	      }
533	      __syncthreads();
534	      cp_async::pred_load<vec_bits, PrefetchMode::kPrefetch, SharedMemFillMode::kNoFill>(
535	          v_smem + ((iter % num_smem_stages) * bdy + ty) * head_dim + tx * vec_size,
536	          V +
537	              ((indptr[pos] + ((iter + num_smem_stages) * bdy + ty)) * num_heads + head_idx) *
538	                  head_dim +
539	              tx * vec_size,
540	          (iter + num_smem_stages) * bdy + ty < num_index_sets);
541	      cp_async::commit_group();
542	    }
543	    cp_async::wait_group<0>();
544	    __syncthreads();
545	
546	    threadblock_sum<bdx, bdy, vec_size>(v_sum_vec, v_smem);
547	
548	    v_sum_vec.cast_store(v_sum + (pos * num_heads + head_idx) * head_dim + tx * vec_size);
549	  }
550	#if (__CUDACC_VER_MAJOR__ >= 12 && defined(__CUDA_ARCH__) && (__CUDA_ARCH__ >= 900))
551	  asm volatile("griddepcontrol.launch_dependents;");
552	#endif
553	}
554	
555	/*!
556	 * \brief Merge the self-attention state of two index sets A and B.
557	 * \tparam DTypeIn The data type of v_a and v_b.
558	 * \tparam DTypeO The data type of v_merged.
559	 * \param v_a The partial v of index set A (n, h, d)
560	 * \param s_a The logsumexp value of index set A. (n, h)
561	 * \param v_b The partial v of index set B. (n, h, d)
562	 * \param s_b The logsumexp value of index set B. (n, h)
563	 * \param v_merged The merged v of index set A union B. (n, h, d)
564	 * \param s_merged The merged logsumexp value of index set A union B. (n, h)
565	 * \param seq_len The sequence length.
566	 * \param num_heads The number of heads of v_a and v_b.
567	 * \param head_dim The dimension of each head.
568	 * \param stream The CUDA stream to execute the kernel.
569	 * \return status Indicates whether CUDA calls are successful
570	 * \note Both s_a and s_b are logsumexp values with base 2.
571	 */
572	template <typename DTypeIn, typename DTypeO>
573	cudaError_t MergeState(DTypeIn* v_a, float* s_a, DTypeIn* v_b, float* s_b, DTypeO* v_merged,
574	                       float* s_merged, uint32_t seq_len, uint32_t num_heads, uint32_t head_dim,
575	                       cudaStream_t stream = nullptr) {
576	  DISPATCH_HEAD_DIM(head_dim, HEAD_DIM, {
577	    constexpr uint32_t vec_size = std::max(16U / sizeof(DTypeIn), HEAD_DIM / 32U);
578	    uint32_t bdx = HEAD_DIM / vec_size;
579	    uint32_t bdy = num_heads;
580	    dim3 nblks(seq_len);
581	    dim3 nthrs(bdx, bdy);
582	    auto kernel = MergeStateKernel<vec_size, DTypeIn, DTypeO>;
583	    void* args[] = {&v_a, &s_a, &v_b, &s_b, &v_merged, &s_merged, &num_heads, &head_dim};
584	    FLASHINFER_CUDA_CALL(cudaLaunchKernel((void*)kernel, nblks, nthrs, args, 0, stream));
585	  });
586	  return cudaSuccess;
587	}
588	
589	/*!
590	 * \brief Merge the self-attention state with another state in place.
591	 * \tparam DType The data type of v and v_other.
592	 * \param v The partial v to be updated in-place. (n, h, d)
593	 * \param s The logsumexp value to be updated in-place. (n, h)
594	 * \param v_other The other v to be merged. (n, h, d)
