602	 * \note Both s and s_other are logsumexp values with base 2.
603	 */
604	template <typename DType>
605	cudaError_t MergeStateInPlace(DType* v, float* s, DType* v_other, float* s_other, uint32_t seq_len,
606	                              uint32_t num_heads, uint32_t head_dim, uint8_t* mask = nullptr,
607	                              cudaStream_t stream = nullptr) {
608	  DISPATCH_HEAD_DIM(head_dim, HEAD_DIM, {
609	    constexpr uint32_t vec_size = std::max(16U / sizeof(DType), HEAD_DIM / 32U);
610	    uint32_t bdx = HEAD_DIM / vec_size;
611	    uint32_t bdy = num_heads;
612	    dim3 nblks(seq_len);
613	    dim3 nthrs(bdx, bdy);
614	    auto kernel = MergeStateInPlaceKernel<vec_size, DType>;
615	    void* args[] = {&v, &s, &v_other, &s_other, &mask, &num_heads, &head_dim};
616	    FLASHINFER_CUDA_CALL(cudaLaunchKernel((void*)kernel, nblks, nthrs, args, 0, stream));
617	  });
618	  return cudaSuccess;
619	}
