621	/*!
622	 * \brief Merge self-attention states of a list of index sets.
623	 * \tparam DTypeIn The data type of v.
624	 * \tparam DTypeO The data type of v_merged.
625	 * \param v The partial v of index sets. (n, num_index_sets, h, d)
626	 * \param s The logsumexp value of index sets. (n, num_index_sets, h)
627	 * \param v_merged The merged v of index sets union. (n, h, d)
628	 * \param s_merged The merged logsumexp value of index sets union. (n, h)
629	 * \param num_index_sets The number of index sets.
630	 * \param seq_len The sequence length.
631	 * \param num_heads The number of heads of v.
632	 * \param head_dim The dimension of each head.
633	 * \param stream The CUDA stream to execute the kernel.
634	 * \return status Indicates whether CUDA calls are successful
635	 * \note s are logsumexp values with base 2.
636	 */
637	template <typename DTypeIn, typename DTypeO>
638	cudaError_t MergeStates(DTypeIn* v, float* s, DTypeO* v_merged, float* s_merged,
639	                        uint32_t num_index_sets, uint32_t seq_len, uint32_t num_heads,
640	                        uint32_t head_dim, cudaStream_t stream = nullptr) {
641	  DISPATCH_HEAD_DIM(head_dim, HEAD_DIM, {
642	    constexpr uint32_t vec_size = std::max(16U / sizeof(DTypeIn), HEAD_DIM / 32U);
643	    constexpr uint32_t bdx = HEAD_DIM / vec_size;
644	    if (num_index_sets >= seq_len) {
645	      constexpr uint32_t num_threads = 128;
646	      constexpr uint32_t bdy = num_threads / bdx;
647	      dim3 nblks(seq_len, num_heads);
648	      dim3 nthrs(bdx, bdy);
649	      constexpr uint32_t num_smem_stages = 4;
650	      auto kernel =
651	          MergeStatesLargeNumIndexSetsKernel<vec_size, bdx, bdy, num_smem_stages, DTypeIn, DTypeO>;
652	      void* args[] = {&v, &s, &v_merged, &s_merged, &num_index_sets, &num_heads};
653	      uint32_t smem_size =
654	          num_smem_stages * bdy * head_dim * sizeof(DTypeIn) + num_threads * sizeof(float);
655	      FLASHINFER_CUDA_CALL(
656	          cudaFuncSetAttribute(kernel, cudaFuncAttributeMaxDynamicSharedMemorySize, smem_size));
657	      FLASHINFER_CUDA_CALL(cudaLaunchKernel((void*)kernel, nblks, nthrs, args, smem_size, stream));
658	    } else {
659	      uint32_t bdy = num_heads;
660	      dim3 nblks(seq_len);
661	      dim3 nthrs(bdx, bdy);
662	      auto kernel = MergeStatesKernel<vec_size, DTypeIn, DTypeO>;
663	      void* args[] = {&v, &s, &v_merged, &s_merged, &num_index_sets, &num_heads, &head_dim};
664	      FLASHINFER_CUDA_CALL(cudaLaunchKernel((void*)kernel, nblks, nthrs, args, 0, stream));
665	    }
666	  });
667	  return cudaSuccess;
668	}
