686	template <typename DTypeIn, typename DTypeO, typename IdType>
687	cudaError_t VariableLengthMergeStates(DTypeIn* v, float* s, IdType* indptr, DTypeO* v_merged,
688	                                      float* s_merged, uint32_t max_seq_len, uint32_t* seq_len,
689	                                      uint32_t num_heads, uint32_t head_dim, bool enable_pdl,
690	                                      cudaStream_t stream = nullptr) {
691	  int dev_id = 0;
692	  int num_sms = 0;
693	  int num_blocks_per_sm = 0;
694	  FLASHINFER_CUDA_CALL(cudaGetDevice(&dev_id));
695	  FLASHINFER_CUDA_CALL(cudaDeviceGetAttribute(&num_sms, cudaDevAttrMultiProcessorCount, dev_id));
696	
697	  DISPATCH_HEAD_DIM(head_dim, HEAD_DIM, {
698	    constexpr uint32_t vec_size = std::max(16U / sizeof(DTypeIn), HEAD_DIM / 32U);
699	    constexpr uint32_t bdx = HEAD_DIM / vec_size;
700	    constexpr uint32_t num_threads = 128;
701	    constexpr uint32_t bdy = num_threads / bdx;
702	    constexpr uint32_t num_smem_stages = 4;
703	    uint32_t smem_size =
704	        num_smem_stages * bdy * head_dim * sizeof(DTypeIn) + num_threads * sizeof(float);
705	    auto kernel = PersistentVariableLengthMergeStatesKernel<vec_size, bdx, bdy, num_smem_stages,
706	                                                            DTypeIn, DTypeO, IdType>;
707	    FLASHINFER_CUDA_CALL(cudaOccupancyMaxActiveBlocksPerMultiprocessor(&num_blocks_per_sm, kernel,
708	                                                                       num_threads, smem_size));
709	    num_blocks_per_sm = min(num_blocks_per_sm, ceil_div(max_seq_len * num_heads, num_sms));
710	
711	    dim3 nblks(num_sms * num_blocks_per_sm);
712	    dim3 nthrs(bdx, bdy);
713	    void* args[] = {&v, &s, &indptr, &v_merged, &s_merged, &max_seq_len, &seq_len, &num_heads};
714	    FLASHINFER_CUDA_CALL(
715	        cudaFuncSetAttribute(kernel, cudaFuncAttributeMaxDynamicSharedMemorySize, smem_size));
716	
717	    // PDL launch
718	    if (enable_pdl) {
719	      cudaLaunchAttribute attribute[1];
720	      attribute[0].id = cudaLaunchAttributeProgrammaticStreamSerialization;
721	      attribute[0].val.programmaticStreamSerializationAllowed = 1;
722	      cudaLaunchConfig_t config;
723	      config.attrs = attribute;
724	      config.numAttrs = 1;
725	      config.gridDim = nblks;
726	      config.blockDim = nthrs;
727	      config.dynamicSmemBytes = smem_size;
728	      config.stream = stream;
729	      FLASHINFER_CUDA_CALL(cudaLaunchKernelEx(&config, kernel, v, s, indptr, v_merged, s_merged,
730	                                              max_seq_len, seq_len, num_heads));
731	    } else {
732	      FLASHINFER_CUDA_CALL(cudaLaunchKernel((void*)kernel, nblks, nthrs, args, smem_size, stream));
733	    }
734	  });
735	  return cudaSuccess;
736	}
